import{_ as e,o,c as r,a2 as d}from"./chunks/framework.CHSDihme.js";const m=JSON.parse('{"title":"Cursor Agent workflow（私有仓）","description":"","frontmatter":{},"headers":[],"relativePath":"reference/cursor-agent-workflow.md","filePath":"reference/cursor-agent-workflow.md","lastUpdated":1781108968000}'),a={name:"reference/cursor-agent-workflow.md"};function i(n,t,l,s,c,u){return o(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="cursor-agent-workflow私有仓" tabindex="-1">Cursor Agent workflow（私有仓） <a class="header-anchor" href="#cursor-agent-workflow私有仓" aria-label="Permalink to &quot;Cursor Agent workflow（私有仓）&quot;">​</a></h1><p>Workflow 文件：<code>.github/workflows/cursor-agent.yml</code></p><p>在 GitHub Actions 里手动 <strong>Run workflow</strong> 触发，需要 Secret <code>CURSOR_API_KEY</code>。</p><h2 id="modeaudit-vs-implement" tabindex="-1">mode：audit vs implement <a class="header-anchor" href="#modeaudit-vs-implement" aria-label="Permalink to &quot;mode：audit vs implement&quot;">​</a></h2><table tabindex="0"><thead><tr><th>mode</th><th>用途</th><th>会改代码？</th><th>会推分支？</th></tr></thead><tbody><tr><td><strong>audit</strong></td><td>看项目、找改善点、架构/代码评审</td><td><strong>否</strong></td><td><strong>否</strong></td></tr><tr><td><strong>implement</strong></td><td>明确要 Agent 改代码（修 bug、小功能）</td><td>是</td><td>是（有改动时）</td></tr></tbody></table><p><strong>调研 / 「有没有值得改善的地方」类任务请选 <code>audit</code>。</strong></p><h3 id="audit-模式" tabindex="-1">audit 模式 <a class="header-anchor" href="#audit-模式" aria-label="Permalink to &quot;audit 模式&quot;">​</a></h3><ul><li>Agent 只能阅读、搜索、分析；报告写在 <strong>Actions 日志</strong>里。</li><li>查看路径：Actions → 对应 run → 步骤 <strong>Run Cursor Agent (audit — read only)</strong> 的完整 stdout。</li><li>若 Agent 仍改了文件，workflow 会在 <strong>Reject audit workspace mutations</strong> 步骤 <strong>失败</strong>，并列出 diff，<strong>不会</strong> push 分支。</li></ul><h3 id="implement-模式" tabindex="-1">implement 模式 <a class="header-anchor" href="#implement-模式" aria-label="Permalink to &quot;implement 模式&quot;">​</a></h3><ul><li>Agent 可改业务文件（仍禁止改 workflow、根 package.json、Tauri 等，见 workflow 内提示）。</li><li>有改动时推 <code>cursor/agent-&lt;run_id&gt;</code>；<code>create_pr=true</code> 时自动开 PR。</li><li><code>verify_mode</code>：<code>narrow</code> / <code>verify</code> / <code>skip</code>（默认 skip）。</li></ul><h2 id="常用-dispatch-示例" tabindex="-1">常用 dispatch 示例 <a class="header-anchor" href="#常用-dispatch-示例" aria-label="Permalink to &quot;常用 dispatch 示例&quot;">​</a></h2><p><strong>只读评审（推荐用于 #5 那种任务）：</strong></p><ul><li>mode: <code>audit</code></li><li>prompt: <code>通读 desktop 与 server 核心路径，列出按优先级排序的改善建议，不要改任何文件。</code></li></ul><p><strong>修 CI / 改代码：</strong></p><ul><li>mode: <code>implement</code></li><li>verify_mode: <code>narrow</code> 或 <code>verify</code>（按需）</li><li>create_pr: 按需</li></ul><h2 id="输出在哪里" tabindex="-1">输出在哪里 <a class="header-anchor" href="#输出在哪里" aria-label="Permalink to &quot;输出在哪里&quot;">​</a></h2><table tabindex="0"><thead><tr><th>mode</th><th>结论 / diff</th></tr></thead><tbody><tr><td>audit</td><td>仅 Actions 日志（无 PR、无分支）</td></tr><tr><td>implement</td><td>日志 + <code>cursor/agent-&lt;run_id&gt;</code> 分支 compare</td></tr></tbody></table><p>Run URL 形如：<code>https://github.com/hyqibot/claude-code-private/actions/runs/&lt;run_id&gt;</code></p>',18)])])}const p=e(a,[["render",i]]);export{m as __pageData,p as default};
